const results = [];
for (const item of $input.all()) {
  const raw = item.json;
  const jobs = raw.data || [];
  for (const job of jobs) {
    const attrs = job.attributes || {};
    const cargo = (attrs.title || '').trim();
    if (!cargo) continue;
    const companySlug = job.relationships?.company?.data?.id || '';
    const empresa = companySlug ? companySlug.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ') : 'Empresa';
    const url = job.links?.public_url || ('https://www.getonbrd.com/jobs/' + (job.id || ''));
    const fechaTs = attrs.published_at ? attrs.published_at * 1000 : Date.now();
    const fechaPublicacion = new Date(fechaTs).toISOString().split('T')[0];
    const modalidad = attrs.remote_modality === 'full' ? 'Remoto' : attrs.remote_modality === 'hybrid' ? 'Híbrido' : 'Presencial';
    const descripcion = (attrs.description || '').replace(/<[^>]+>/g, '').substring(0, 500);
    results.push({ json: { cargo, empresa, ciudad: modalidad === 'Remoto' ? 'Remoto' : 'Santiago', url, descripcion, portal: 'GetOnBoard', fechaPublicacion, salarioMin: attrs.min_salary || 0, salarioMax: attrs.max_salary || 0 } });
  }
}
return results.length ? results : [{ json: { _noResults: true, portal: 'GetOnBoard' } }];

const body = $input.first().json;

if (body.code === 'ERR_BAD_REQUEST' || (typeof body.status === 'number' && body.status >= 400) || body.name === 'AxiosError') {
  return [];
}

const jobs = body.offers || body.data || body.results || body.jobs || (Array.isArray(body) ? body : []);
if (!Array.isArray(jobs) || jobs.length === 0) return [];

return jobs.map(job => ({
  json: {
    cargo: job.titulo || job.title || job.nombre || '',
    empresa: job.empresa || job.company || job.employer || '',
    ciudad: job.ciudad || job.location || job.region || 'Santiago',
    url: job.url || job.link || '',
    descripcion: (job.descripcion || job.description || '').replace(/<[^>]*>/g, '').slice(0, 4000),
    portal: 'Indeed Chile',
    fechaPublicacion: job.fecha || job.date || job.published_at || new Date().toISOString(),
    metodoPago: 'formulario',
    salarioMin: null,
    salarioMax: null,
    idExterno: String(job.id || job.oferta_id || '')
  }
})).filter(item => item.json.cargo !== '');

const items = $input.all().filter(i => !i.json._empty);
const KEYWORDS = ['analista', 'automatizacion', 'automatización', 'procesos', 'control gestion', 'gestión', 'operaciones', 'consultor', 'sistemas', 'datos', ' bi ', 'erp', 'mejora continua', 'kpi', 'proyectos'];
const CIUDADES = ['santiago', 'valparaíso', 'valparaiso', 'remoto', 'remote', 'teletrabajo', 'híbrido', 'hibrido', 'presencial'];
const HOY = new Date();
const SIETE_DIAS = 7 * 24 * 60 * 60 * 1000;

const filtered = items.filter(item => {
  const j = item.json;
  if (!j.cargo) return false;
  const cargo = (j.cargo || '').toLowerCase();
  const ciudad = (j.ciudad || '').toLowerCase();
  const fecha = j.fechaPublicacion ? new Date(j.fechaPublicacion) : HOY;

  const tieneKeyword = KEYWORDS.some(k => cargo.includes(k));
  const ciudadOk = CIUDADES.some(c => ciudad.includes(c)) || ciudad === '';
  const reciente = (HOY - fecha) <= SIETE_DIAS;

  return tieneKeyword && ciudadOk && reciente;
});

if (filtered.length === 0) {
  return [{ json: { _noResults: true, _totalScraped: items.length } }];
}
return filtered;

// Notion result is the current input item
const notionData = $input.item.json;

// Get the original job item paired with this execution
let jobJson = null;
try {
  const pairedItem = $('\u00bfSin ofertas?').item;
  if (
    pairedItem &&
    pairedItem.json &&
    typeof pairedItem.json === 'object' &&
    !Array.isArray(pairedItem.json) &&
    !pairedItem.json.error
  ) {
    jobJson = pairedItem.json;
  }
} catch (e) {}

// If job lookup failed, try input item directly
if (!jobJson) {
  const inp = $input.item.json;
  if (
    inp &&
    typeof inp === 'object' &&
    !Array.isArray(inp) &&
    !inp.error &&
    inp.titulo
  ) {
    jobJson = inp;
  }
}

// Still no job — skip item
if (!jobJson || typeof jobJson !== 'object' || Array.isArray(jobJson)) {
  return [];
}

// If Notion errored — pass job through (fail-safe)
const notionOk = notionData && !notionData.error && Array.isArray(notionData.results);
if (!notionOk) {
  return [{ json: jobJson }];
}

// Extract existing URLs from Notion pages
const existingUrls = new Set();
for (const page of notionData.results) {
  const url = page.properties?.['Link\ud83d\udd39']?.url
           || page.properties?.['Link']?.url
           || page.properties?.['URL']?.url
           || page.properties?.['url']?.url
           || '';
  if (url) existingUrls.add(url.trim());
}

// Check if job URL is already in Notion
const jobUrl = (jobJson.url || '').trim();
const isDuplicate = jobUrl && existingUrls.has(jobUrl);

if (isDuplicate) {
  return [];
}

return [{ json: jobJson }];

const claudeResp = $input.item.json;
let offerData = {};
try { offerData = $('Descartar Duplicados').item.json; } catch(e) {}

let scoreData = { score: 0, justificacion: 'Error parsing', keywords: [], emailContacto: null };

try {
  const content = claudeResp.choices?.[0]?.message?.content || claudeResp.content?.[0]?.text || '';
  const match = content.match(/\{[\s\S]*\}/);
  if (match) scoreData = JSON.parse(match[0]);
} catch(e) {
  scoreData.justificacion = 'Parse error: ' + String(e.message).slice(0,50);
}

return [{
  json: {
    ...offerData,
    score: scoreData.score || 0,
    justificacion: scoreData.justificacion || '',
    keywords: scoreData.keywords || [],
    emailContacto: scoreData.emailContacto || null
  }
}];

const items = $input.all();
const hoy = new Date().toLocaleDateString('es-CL', {day:'2-digit', month:'2-digit', year:'numeric'});

const autoEnviar = items.filter(i => i.json.score >= 8 && i.json.emailContacto);
const revisar = items.filter(i => i.json.score >= 5 && !(i.json.score >= 8 && i.json.emailContacto));

let text = `☀️ *Resumen matutino — ${hoy}*\n\n`;

if (autoEnviar.length > 0) {
  text += `✅ *Envío automático: ${autoEnviar.length} oferta${autoEnviar.length>1?'s':''}*\n`;
  autoEnviar.forEach((item, i) => {
    const j = item.json;
    text += `${i+1}. *${j.cargo}* en ${j.empresa} | Score: ${j.score}/10 | ${j.portal}\n`;
  });
  text += '\n';
}

if (revisar.length > 0) {
  text += `👀 *Para revisar: ${revisar.length} oferta${revisar.length>1?'s':''}*\n`;
  revisar.forEach((item, i) => {
    const j = item.json;
    const idx = autoEnviar.length + i + 1;
    text += `${idx}. *${j.cargo}* en ${j.empresa} | Score: ${j.score}/10\n📎 ${j.url || 'sin URL'}\n`;
  });
}

const totalItems = items.length;
text += `\n📊 2 portales | ${totalItems} analizadas | ${autoEnviar.length + revisar.length} con score≥5`;

return [{ json: { text, autoEnviar: autoEnviar.map(i=>i.json), revisar: revisar.map(i=>i.json) } }];

// Parsear Email — Run Once for All Items
const claudeItem = $input.first();
const content = String(claudeItem.json.choices?.[0]?.message?.content || claudeItem.json.content?.[0]?.text || '');

let emailAsunto = '';
let emailCuerpo = '';
try {
  const match = content.match(/\{[\s\S]+\}/);
  if (match) {
    const emailData = JSON.parse(match[0]);
    if (emailData.asunto) emailAsunto = String(emailData.asunto);
    if (emailData.cuerpo) emailCuerpo = String(emailData.cuerpo);
  }
} catch(e) {}

let cargo = '', empresa = '', emailContacto = '', portal = '', url = '', score = 0;
try {
  const j = $('Reagrupar Datos + PDF').first().json;
  cargo = String(j.cargo || '');
  empresa = String(j.empresa || '');
  emailContacto = String(j.emailContacto || '');
  portal = String(j.portal || '');
  url = String(j.url || '');
  score = Number(j.score || 0);
} catch(e) {}

if (!emailAsunto) {
  emailAsunto = 'Postulación ' + (cargo || 'Cargo') + ' — Simón Marín Rojas | Ingeniero Comercial';
}

const result = {};
result.cargo = cargo;
result.empresa = empresa;
result.emailContacto = emailContacto;
result.portal = portal;
result.url = url;
result.score = score;
result.emailAsunto = emailAsunto;
result.emailCuerpo = emailCuerpo;

const out = { json: result };

try {
  const reagruparItem = $('Reagrupar Datos + PDF').first();
  if (reagruparItem.binary && reagruparItem.binary.cvPDF) {
    out.binary = { cvPDF: reagruparItem.binary.cvPDF };
  }
} catch(e) {}

return [out];

const response = $input.first().json;

if (response.code === 'ERR_BAD_REQUEST' || (typeof response.status === 'number' && response.status >= 400) || response.name === 'AxiosError') {
  return [];
}

let jobs = [];
if (Array.isArray(response)) {
  jobs = response;
} else if (Array.isArray(response.data)) {
  jobs = response.data;
}

if (jobs.length === 0) return [];

return jobs.map(job => ({
  json: {
    cargo: job.positionName || job.title || '',
    empresa: job.company || '',
    ciudad: (job.location || '').toLowerCase().includes('remote') || (job.location || '').toLowerCase().includes('remoto') ? 'Remoto' : (job.location || 'Santiago'),
    url: job.url || job.externalApplyLink || '',
    descripcion: (job.description || job.jobDescription || '').replace(/<[^>]*>/g, '').substring(0, 4000),
    portal: 'Indeed Chile',
    fechaPublicacion: job.postedAt || job.date || new Date().toISOString(),
    metodoPago: job.externalApplyLink ? 'email' : 'formulario',
    salarioMin: null,
    salarioMax: null
  }
})).filter(item => item.json.cargo !== '');

const sd = $getWorkflowStaticData('global');
const execId = $execution.id;

// Dedup: si ya procese este execId, no emito nada
if (sd.lastRouterExecId === execId) {
  return [];
}
sd.lastRouterExecId = execId;

const allItems = $input.all();
const realItems = allItems.filter(i => !i.json._empty && i.json.cargo && i.json.cargo !== '');

if (realItems.length === 0) {
  return [{ json: { _noOffers: true } }];
}

return realItems.map(i => ({ json: { ...i.json, _noOffers: false } }));

// ── ARMAR CV HTML v4.1 ── Mode: runOnceForAllItems
const item = $input.first();
const cvRaw = item.json?.choices?.[0]?.message?.content || item.json?.content?.[0]?.text || '';

let cargo = '', empresa = '', emailContacto = '', resumen = '', bullets = [], keywords = [], emailCuerpo = '';
try {
  const jsonMatch = cvRaw.match(/```json\n([\s\S]*?)\n```/) || cvRaw.match(/\{[\s\S]*\}/);
  const parsed = JSON.parse(jsonMatch ? jsonMatch[1] || jsonMatch[0] : cvRaw);
  cargo = parsed.cargo || '';
  empresa = parsed.empresa || '';
  emailContacto = parsed.emailContacto || parsed.emailDestino || '';
  resumen = parsed.resumen || '';
  bullets = parsed.bullets || [];
  keywords = parsed.keywords || [];
  emailCuerpo = parsed.emailCuerpo || '';
} catch(e) {
  cargo = item.json?.cargo || '';
  empresa = item.json?.empresa || '';
  emailContacto = item.json?.emailContacto || '';
  resumen = item.json?.resumen || '';
  bullets = item.json?.bullets || [];
  keywords = item.json?.keywords || [];
  emailCuerpo = item.json?.emailCuerpo || '';
}

const display = bullets.slice(0, 4);

const iconDoc = `<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="#1a6cb5" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:middle;margin-right:7px;flex-shrink:0"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/></svg>`;
