<div class="contact-bar">
  <div class="ci">
    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="#1a6cb5" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="2" y="4" width="20" height="16" rx="2"/><polyline points="2,4 12,13 22,4"/></svg>
