    Santiago, Chile
  </div>
</div>
<div class="content">

  <h2>${iconDoc}Resumen Profesional</h2>
  <div class="summary"><p>${resumen}</p></div>

  <h2>${iconGrad}Educación</h2>
  <div class="edu-block">
