  <h2>${iconBrief}Experiencia Profesional</h2>

  <div class="job">
    <div class="job-row">
      <span class="job-company">Constructora Bioproterra SpA</span>
      <span class="job-meta">Dic. 2022 – Presente &nbsp;·&nbsp; Santiago, Chile</span>
    </div>
