    <ul>
      ${display.map(b => `<li>${b}</li>`).join('\n      ')}
    </ul>
  </div>

  <div class="job">
    <div class="job-row">
      <span class="job-company">Restaurante Mistral</span>
      <span class="job-meta">Ago. – Dic. 2023 &nbsp;·&nbsp; Coquimbo, Chile</span>
    </div>
    <div class="job-title">Asesor en Marketing</div>
    <ul>
      <li>Desarrollé diagnóstico comercial integral, lineamientos de branding, comunicación corporativa y campañas digitales para PYME gastronómica, logrando posicionamiento en canal digital desde cero.</li>
